import { lzcAPIGateway } from "@lazycatcloud/sdk"

const grpc = new lzcAPIGateway("/_lzc/runtime/grpc/");

const getBoxName = async () => {
  const boxInfo = await grpc.box.QueryInfo({});
  return boxInfo.boxName;
};

export async function getFileDomain(boxId?: string) {
  if (boxId) {
    return `file.${boxId}.heiyu.space`;
  }
  try {
    const result = await grpc.pkgm.QueryApplication({
      deployIds: ["cloud.lazycat.shell.files"],
    });
    const [info] = result.infoList;
    return info.domain;
  } catch (error) {
    const boxName = await getBoxName();
    return `file.${boxName}.heiyu.space`;
  }
}
