export enum filePickerType {
  file = "file",
  directory = "directory",
}
export enum tableListType {
  collect = "collect",
  networkDir = "networkDir",
  externalHardDrive = "externalHardDrive",
  appData = "appData",
  fileMount = "fileMount",
}
export interface filePickerPropsType {
  /**
   * @deprecated
   * 
   * 内部自行判断不需要传递
   */
  boxId?: string;
  type: filePickerType;
  title?: string;
  rootpath?: string;
  rootname?: string;
  source?: string[]; // 底部名称字段透传（undefined不显示，[]禁用确认）
  accept?: string; //过滤
  extname?: string; //过滤
  filterSelectVisible?: boolean; // 是否显示扩展名过滤切换下拉
  confirmButtonTitle?: string; //确认标题
  tableList?: tableListType[]; //显示哪些table
  multiple?: boolean; //是否多选
  isModal?: boolean //是否是弹窗
  choiceFileOnly?: boolean //是否只选择文件
  choiceDirOnly?: boolean //是否只选择文件夹
  ignorePath?: string[] //过滤路径
}
